// src/components/MapComponent.js
import React, { useMemo } from "react";
import { GoogleMap, Marker, useJsApiLoader } from "@react-google-maps/api";

/**
 * vehicles: optional array, each item can have:
 * - { lat, lng }
 * - { latitude, longitude }
 * - { coords: [lat, lng] }
 * - { location: "lat,lng" }
 * - optional id or license_plate for keys/titles
 */
export default function MapComponent({ vehicles = [] }) {
  // Load Maps JS API once and show a lightweight fallback until ready
  const { isLoaded } = useJsApiLoader({
    googleMapsApiKey: process.env.REACT_APP_GOOGLE_MAPS_API_KEY || "",
  });

  // Default center (Bengaluru) – change if needed
  const center = useMemo(() => ({ lat: 12.9716, lng: 77.5946 }), []);

  // Normalize vehicle positions into {lat, lng}[]
  const positions = useMemo(() => {
    return vehicles
      .map((v) => {
        if (typeof v?.lat === "number" && typeof v?.lng === "number") {
          return { lat: v.lat, lng: v.lng };
        }
        if (
          typeof v?.latitude === "number" &&
          typeof v?.longitude === "number"
        ) {
          return { lat: v.latitude, lng: v.longitude };
        }
        if (Array.isArray(v?.coords) && v.coords.length === 2) {
          const [a, b] = v.coords;
          if (typeof a === "number" && typeof b === "number") {
            return { lat: a, lng: b };
          }
        }
        if (typeof v?.location === "string") {
          const [a, b] = v.location
            .split(",")
            .map((s) => parseFloat(String(s).trim()));
          if (!Number.isNaN(a) && !Number.isNaN(b)) {
            return { lat: a, lng: b };
          }
        }
        return null;
      })
      .filter(Boolean);
  }, [vehicles]);

  if (!isLoaded) return <div>Loading map…</div>;

  return (
    <GoogleMap
      center={positions || center}
      zoom={positions.length ? 11 : 10}
      // IMPORTANT: set explicit height so the map is visible
      mapContainerStyle={{ width: "100%", height: "360px" }}
      options={{
        streetViewControl: false,
        mapTypeControl: false,
        fullscreenControl: false,
      }}
    >
      {positions.map((pos, i) => (
        <Marker
          key={vehicles[i]?.id ?? vehicles[i]?.license_plate ?? i}
          position={pos}
          title={
            vehicles[i]?.license_plate ??
            vehicles[i]?.licensePlate ??
            `Vehicle ${i + 1}`
          }
        />
      ))}
    </GoogleMap>
  );
}
